// Classify each paper with Groq — async fetch keeps paper metadata in scope
const items = $input.all();
const GROQ_KEY = 'YOUR_GROQ_API_KEY';
const results = [];

for (const item of items) {
  let groqLabel = 'uncertain', confidence = 0.5, groqReason = 'n/a';
  try {
    const resp = await fetch('https://api.groq.com/openai/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + GROQ_KEY,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: 'llama-3.3-70b-versatile',
        temperature: 0.1,
        max_tokens: 120,
        messages: [
          {
            role: 'system',
            content: 'Classify research papers for Cambodia National AI Strategy 2025-2030. Reply ONLY with valid JSON (no markdown, no explanation): {"label":"relevant|irrelevant|uncertain","confidence":0.0-1.0,"reason":"max 10 words"}'
          },
          {
            role: 'user',
            content: 'Title: ' + item.json.title + '\n\nAbstract: ' + (item.json.abstract || '').substring(0, 500)
          }
        ]
      })
    });
    const data = await resp.json();
    const raw = data.choices[0].message.content.trim().replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(raw);
    groqLabel = ['relevant', 'irrelevant', 'uncertain'].includes(parsed.label) ? parsed.label : 'uncertain';
    confidence = Math.min(1, Math.max(0, parseFloat(parsed.confidence) || 0.5));
    groqReason = (parsed.reason || '').substring(0, 80);
  } catch (e) {
    groqReason = 'error: ' + String(e.message || '').substring(0, 40);
  }

  results.push({ json: {
    paper_id: item.json.paper_id,
    title: item.json.title,
    abstract: item.json.abstract,
    source: item.json.source,
    groq_label: groqLabel,
    confidence,
    groq_reason: groqReason
  }});
}
return results;

