// Build Telegram HTML message with clickable label links
const item = $input.first().json;
const BASE = 'https://YOUR_INSTANCE.app.n8n.cloud/webhook/hitl-label';
const pid  = encodeURIComponent(item.paper_id);
const pct  = Math.round((item.confidence || 0) * 100);
const esc  = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const title    = esc((item.title    || '').substring(0, 120));
const reason   = esc((item.groq_reason || ''));
const abstract = esc((item.abstract || '').substring(0, 260));

const text = [
  '🔬 <b>Paper Review Request</b>',
  '',
  `<b>Title:</b> ${title}`,
  `<b>Source:</b> ${esc(item.source || '?')}  |  <b>AI Confidence:</b> ${pct}%`,
  `<b>AI Guess:</b> ${esc(item.groq_label)}  —  <i>${reason}</i>`,
  '',
  `<b>Abstract:</b>\n${abstract}…`,
  '',
  '<b>▸ Tap to label:</b>',
  `✅ <a href="${BASE}?paper_id=${pid}&label=relevant">Relevant</a>   ❌ <a href="${BASE}?paper_id=${pid}&label=irrelevant">Not Relevant</a>   🤔 <a href="${BASE}?paper_id=${pid}&label=uncertain">Uncertain</a>`
].join('\n');

return [{ json: { text, paper_id: item.paper_id, confidence: item.confidence, groq_label: item.groq_label, groq_reason: item.groq_reason } }];

